from dataclasses import dataclass
from enum import Enum
from typing import Optional

class DataAccessStatus(str, Enum):
    CONFIRMED   = "confirmed"    # Access tested; schema reviewed
    PENDING     = "pending"      # Ticket open; verbal confirmation only
    BLOCKED     = "blocked"      # Access denied or licence issue
    NOT_NEEDED  = "not_needed"   # Not required for sprint-1

@dataclass
class DataSourceReadiness:
    source_name: str
    sprint_needed: int            # First sprint that needs this source
    access_status: DataAccessStatus
    pii_fields_identified: bool
    pii_handling_agreed: bool
    licence_confirmed: bool
    blocker_ticket: Optional[str] = None  # JIRA/Linear ticket if BLOCKED

    def is_sprint1_ready(self) -> bool:
        if self.sprint_needed > 1 or self.access_status == DataAccessStatus.NOT_NEEDED:
            return True
        return (
            self.access_status == DataAccessStatus.CONFIRMED
            and self.pii_fields_identified
            and self.pii_handling_agreed
            and self.licence_confirmed
        )

    def blockers(self) -> list[str]:
        issues = []
        if self.access_status != DataAccessStatus.CONFIRMED:
            issues.append(f"Access not confirmed ({self.access_status.value})")
        if not self.pii_fields_identified:
            issues.append("PII fields not identified")
        if not self.pii_handling_agreed:
            issues.append("PII handling approach not agreed")
        if not self.licence_confirmed:
            issues.append("Data licence not confirmed for AI use")
        return issues

def handoff_data_gate(sources: list[DataSourceReadiness]) -> tuple[bool, list[str]]:
    """Returns (ready, list_of_blockers)."""
    all_blockers = []
    for s in sources:
        if not s.is_sprint1_ready():
            for b in s.blockers():
                all_blockers.append(f"{s.source_name}: {b}")
    return len(all_blockers) == 0, all_blockers

import json
from datetime import date
from pathlib import Path

GATE_HISTORY_PATH = Path("docs/handoff-gates.json")

def record_gate(gate: HandoffGate, gate_date: date) -> None:
    history = json.loads(GATE_HISTORY_PATH.read_text()) if GATE_HISTORY_PATH.exists() else []
    record = {
        "feature":    gate.feature_name,
        "sprint":     gate.sprint_number,
        "date":       gate_date.isoformat(),
        "status":     gate.overall_status().value,
        "can_start":  gate.can_start_sprint(),
        "criteria":   [
            {"name": c.name, "status": c.status.value, "notes": c.notes}
            for c in gate.criteria
        ],
    }
    history.append(record)
    GATE_HISTORY_PATH.write_text(json.dumps(history, indent=2))

def most_common_blockers(history_path: Path = GATE_HISTORY_PATH) -> dict[str, int]:
    """Return count of times each criterion was NOT_READY, across all recorded gates."""
    history = json.loads(history_path.read_text()) if history_path.exists() else []
    counts: dict[str, int] = {}
    for gate in history:
        for c in gate.get("criteria", []):
            if c["status"] == "not_ready":
                counts[c["name"]] = counts.get(c["name"], 0) + 1
    return dict(sorted(counts.items(), key=lambda x: -x[1]))
